    (site/'sovereign-rsi-control-plane.html').write_text(wrap('Sovereign RSI — GoalOS AGIALPHA Ascension','RSI control plane.', f"<section class='shell'><section class='hero'><div class='hero-grid'><div><div class='kicker'>Sovereign RSI</div><h1>Proof-backed upgrade rights control plane</h1><p>RSI means only proven, reviewed, selected work can influence future operating context.</p></div><div class='hero-visual'>{hero_svg()}</div></div></section><section class='panel'>{flow(['Weakness','Candidate','Proof','Review','Selection','Upgrade','Future Work'])}</section></section>"), encoding='utf-8')
