def main():
    ap=argparse.ArgumentParser()
    ap.add_argument('--site', default='site')
    ap.add_argument('--root', default='.')
    args=ap.parse_args()
    root=Path(args.root)
    site=Path(args.site)
    if site.exists():
        # Preserve existing assets but overwrite proof atlas pages.
        pass
    else:
        site.mkdir(parents=True, exist_ok=True)
    write_all(root, site)
    (site/'.nojekyll').write_text('', encoding='utf-8')
    print('Integrated GoalOS AGIALPHA Proof Card 012 and Proof Cards 001-012 into', site)

if __name__=='__main__': main()
